@startuml
skinparam classAttributeIconSize 0
skinparam noteBackgroundColor #FFFFCC
skinparam noteBorderColor #CCCCCC
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor #CCCCCC
  ArrowColor #666666
}

class Component {
  + add(component:Component):void
  + remove(component:Component):void
  + getChild():int
  + operation():void
}

class Composite {
  + add(component:Component):void
  + remove(component:Component):void
  + getChild():int
  + operation():void
}

class Leaf {
  + operation():void
}

class Client {
}

note right of Component
  Component 为所有节点的基类，不管是普通节点还是叶子节点
end note

note right of Composite
  组合可以操作子节点或者叶子节点，但可能不具有叶子节点的某些行为
end note

note right of Leaf
  叶子节点，不能操作子节点
end note

Component <|-- Composite
Component <|-- Leaf
Composite o-- Component
Leaf -- Component
Client ..> Component

class OrganizationComponent {
  + add(component:OrganizationComponent):void
  + print():void
}

class University {
}

class College {
}

class Department {
}

OrganizationComponent <|-- University
OrganizationComponent <|-- College
OrganizationComponent <|-- Department
University o-- OrganizationComponent
College o-- OrganizationComponent
Department o-- OrganizationComponent

@enduml
